code = """import json

# Get all business data from our cached queries
businesses = []

# From cached queries
for key in ['var_functions.query_db:14', 'var_functions.query_db:20', 'var_functions.query_db:26']:
    data = locals()[key]
    if isinstance(data, list):
        businesses.extend(data)
        print(f"Loaded {len(data)} businesses from {key}")
    else:
        print(f"No valid data for {key}")

print(f"Total businesses in cache: {len(businesses)}")

# Build dict by business_id
business_dict = {}
for b in businesses:
    if b and 'business_id' in b:
        business_dict[b['business_id']] = b

print(f"Unique businesses: {len(business_dict)}")

# Load 2018 business refs
refs = locals()['var_functions.query_db:34']
refs_2018 = [r['business_ref'] for r in refs]

# Convert to business_ids
business_ids_2018 = set()
for ref in refs_2018:
    business_id = ref.replace('businessref_', 'businessid_', 1)
    business_ids_2018.add(business_id)

print(f"Unique 2018 business_ids: {len(business_ids_2018)}")

# Check parking for businesses we have
results = []
for biz_id in business_ids_2018:
    if biz_id not in business_dict:
        continue
    
    business = business_dict[biz_id]
    attrs = business.get('attributes')
    if not attrs or attrs == 'None':
        continue
    
    # Check parking
    has_bike = False
    has_business = False
    
    if isinstance(attrs, dict):
        if 'BikeParking' in attrs:
            val = str(attrs['BikeParking']).lower()
            has_bike = val == 'true'
        
        if 'BusinessParking' in attrs:
            parking = attrs['BusinessParking']
            if str(parking).count('True') > 0:
                has_business = True
    
    if has_bike or has_business:
        results.append(biz_id)

print(f"Businesses with parking: {len(results)}")

output = {
    "total_2018_businesses": len(business_ids_2018),
    "fetched_businesses": len(business_dict),
    "with_parking": len(results),
    "remaining_to_fetch": len(business_ids_2018 - set(business_dict.keys()))
}

print('__RESULT__:')
print(json.dumps(output))"""

